SELECT project_id, title, status
FROM projects
WHERE actual_cost = (SELECT MAX(actual_cost) FROM projects);

SELECT * 
FROM projects 
WHERE project_id = 0;

SELECT *
FROM projects
WHERE budget = (SELECT MAX(budget) FROM projects);

SELECT SUM(pc.amount) AS total_cost
FROM project_costs pc
WHERE pc.cost_id = 1;

SELECT title, actual_cost AS total_actual_cost
FROM projects
WHERE project_id = 0;

SELECT SUM(amount) AS total_cost
FROM project_costs
WHERE project_id = 0;

SELECT title, status
FROM projects
ORDER BY project_id;

SELECT COUNT(*) 
FROM project_actions 
WHERE action_date LIKE '2019-%';
